import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException
from werkzeug.exceptions import BadRequest

app = Flask(__name__)

ES_HOSTS = os.getenv("ES_HOSTS", "http://localhost:9200").split(",")
ES_INDEX = os.getenv("ES_INDEX", "products")
ES_REQUEST_TIMEOUT = float(os.getenv("ES_REQUEST_TIMEOUT", "0.5"))
ES_MAX_RETRIES = int(os.getenv("ES_MAX_RETRIES", "2"))
ES_RETRY_ON_TIMEOUT = os.getenv("ES_RETRY_ON_TIMEOUT", "true").lower() == "true"
SEARCH_SIZE_DEFAULT = int(os.getenv("SEARCH_SIZE_DEFAULT", "20"))
SEARCH_SIZE_MAX = int(os.getenv("SEARCH_SIZE_MAX", "50"))
MIN_QUERY_LENGTH = int(os.getenv("MIN_QUERY_LENGTH", "1"))

es = Elasticsearch(
    ES_HOSTS,
    request_timeout=ES_REQUEST_TIMEOUT,
    max_retries=ES_MAX_RETRIES,
    retry_on_timeout=ES_RETRY_ON_TIMEOUT,
)

def clamp(n, smallest, largest):
    return max(smallest, min(n, largest))

def build_search_query(keyword, size):
    return {
        "track_total_hits": False,
        "size": size,
        "_source": {
            "includes": [
                "id",
                "name",
                "brand",
                "category",
                "price",
                "currency",
                "image_url",
                "in_stock",
                "rating",
                "url",
            ]
        },
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": keyword,
                            "type": "best_fields",
                            "fields": [
                                "name^5",
                                "name.ngram^3",
                                "brand^2",
                                "category",
                                "description",
                            ],
                            "operator": "and",
                            "fuzziness": "AUTO",
                        }
                    },
                    {
                        "match_phrase_prefix": {
                            "name": {
                                "query": keyword,
                                "boost": 4
                            }
                        }
                    }
                ],
                "minimum_should_match": 1
            }
        },
        "sort": [
            "_score",
            {"popularity": {"order": "desc"}},
            {"sales_rank": {"order": "asc", "missing": "_last"}}
        ]
    }

@app.errorhandler(BadRequest)
def handle_bad_request(err):
    return jsonify({"error": "bad_request", "message": str(err.description)}), 400

@app.get("/api/search")
def search_products():
    q = request.args.get("q", type=str)
    if q is None:
        raise BadRequest("missing required query parameter: q")

    q = q.strip()
    if len(q) < MIN_QUERY_LENGTH:
        raise BadRequest(f"query parameter q must be at least {MIN_QUERY_LENGTH} character(s)")

    size = clamp(request.args.get("size", default=SEARCH_SIZE_DEFAULT, type=int), 1, SEARCH_SIZE_MAX)

    try:
        response = es.search(
            index=ES_INDEX,
            body=build_search_query(q, size),
            request_timeout=ES_REQUEST_TIMEOUT,
        )
        hits = response.get("hits", {}).get("hits", [])
        products = [
            {
                "id": hit.get("_source", {}).get("id", hit.get("_id")),
                "score": hit.get("_score"),
                **hit.get("_source", {}),
            }
            for hit in hits
        ]
        return jsonify(
            {
                "query": q,
                "count": len(products),
                "products": products,
            }
        ), 200
    except ElasticsearchException:
        return jsonify({"error": "search_unavailable", "message": "search backend unavailable"}), 503

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))